import { useEffect, useState } from "react";

type BatteryManager = {
  charging: boolean;
  chargingTime: number;
  dischargingTime: number;
  level: number;
  addEventListener: (type: "levelchange" | "chargingchange" | "chargingtimechange" | "dischargingtimechange", listener: () => void) => void;
  removeEventListener: (
    type: "levelchange" | "chargingchange" | "chargingtimechange" | "dischargingtimechange",
    listener: () => void,
  ) => void;
} & EventTarget;

type BatteryState = {
  supported: boolean;
  loading: boolean;
  level: number | null;
  charging: boolean | null;
  chargingTime: number | null;
  dischargingTime: number | null;
};

function useBattery(): BatteryState {
  const [state, setState] = useState<BatteryState>({
    supported: true,
    loading: true,
    level: null,
    charging: null,
    chargingTime: null,
    dischargingTime: null,
  });

  useEffect(() => {
    if (typeof window === "undefined")
      return;

    const navigatorWithBattery = navigator as Navigator & {
      getBattery?: () => Promise<BatteryManager>;
    };

    if (!navigatorWithBattery.getBattery) {
      queueMicrotask(() => {
        setState(s => ({
          ...s,
          supported: false,
          loading: false,
        }));
      });
      return;
    }

    let battery: BatteryManager | null = null;

    const updateState = () => {
      if (!battery)
        return;
      setState({
        supported: true,
        loading: false,
        level: battery.level,
        charging: battery.charging,
        chargingTime: battery.chargingTime,
        dischargingTime: battery.dischargingTime,
      });
    };

    navigatorWithBattery.getBattery().then((b) => {
      battery = b;
      updateState();
      b.addEventListener("levelchange", updateState);
      b.addEventListener("chargingchange", updateState);
      b.addEventListener("chargingtimechange", updateState);
      b.addEventListener("dischargingtimechange", updateState);
    });

    return () => {
      if (!battery)
        return;
      battery.removeEventListener("levelchange", updateState);
      battery.removeEventListener("chargingchange", updateState);
      battery.removeEventListener("chargingtimechange", updateState);
      battery.removeEventListener("dischargingtimechange", updateState);
    };
  }, []);

  return state;
}

export default useBattery;

import type { Dispatch, SetStateAction } from "react";

import { useCallback, useState } from "react";

type UseBooleanReturn = {
  value: boolean;
  setValue: Dispatch<SetStateAction<boolean>>;
  setTrue: () => void;
  setFalse: () => void;
  toggle: () => void;
};

function useBoolean(defaultValue = false): UseBooleanReturn {
  if (typeof defaultValue !== "boolean") {
    throw new TypeError("defaultValue must be `true` or `false`");
  }
  const [value, setValue] = useState(defaultValue);

  const setTrue = useCallback(() => {
    setValue(true);
  }, []);

  const setFalse = useCallback(() => {
    setValue(false);
  }, []);

  const toggle = useCallback(() => {
    setValue(x => !x);
  }, []);

  return { value, setValue, setTrue, setFalse, toggle };
}

export default useBoolean;

import { useCallback, useState } from "react";

function oldSchoolCopy(text: string) {
  const tempTextArea = document.createElement("textarea");
  tempTextArea.value = text;
  document.body.appendChild(tempTextArea);
  tempTextArea.select();
  document.execCommand("copy");
  document.body.removeChild(tempTextArea);
}

function useCopyToClipboard() {
  const [state, setState] = useState<string | null>(null);

  const copyToClipboard = useCallback((value: string) => {
    const handleCopy = async () => {
      try {
        if (navigator?.clipboard?.writeText) {
          await navigator.clipboard.writeText(value);
          setState(value);
        }
        else {
          throw new Error("writeText not supported");
        }
      }
      catch {
        oldSchoolCopy(value);
        setState(value);
      }
    };

    handleCopy();
  }, []);

  return [state, copyToClipboard];
}

export default useCopyToClipboard;

import { useCallback, useEffect, useRef, useState } from "react";

type CountdownOptions = {
  countStart: number;

  intervalMs?: number;
  isIncrement?: boolean;

  countStop?: number;
};

type CountdownControllers = {
  startCountdown: () => void;
  stopCountdown: () => void;
  resetCountdown: () => void;
};

export default function useCountdown({
  countStart,
  countStop = 0,
  intervalMs = 1000,
  isIncrement = false,
}: CountdownOptions): [number, CountdownControllers] {
  const savedCallback = useRef(() => {});

  const [count, setCount] = useState(countStart);
  const increment = useCallback(() => setCount(count + 1), [count]);
  const decrement = useCallback(() => setCount(count - 1), [count]);
  const resetCounter = useCallback(() => setCount(countStart), [countStart]);

  const [isCountdownRunning, setIsCountdownRunning] = useState(false);
  const startCountdown = useCallback(() => setIsCountdownRunning(true), []);
  const stopCountdown = useCallback(() => setIsCountdownRunning(false), []);

  // Will set running false and reset the seconds to initial value.
  const resetCountdown = useCallback(() => {
    stopCountdown();
    resetCounter();
  }, [stopCountdown, resetCounter]);

  const countdownCallback = useCallback(() => {
    if (count === countStop) {
      stopCountdown();
      return;
    }

    if (isIncrement) {
      increment();
    }
    else {
      decrement();
    }
  }, [count, countStop, decrement, increment, isIncrement, stopCountdown]);

  useEffect(() => {
    savedCallback.current = countdownCallback;
  });

  const delay = isCountdownRunning ? intervalMs : null;

  useEffect(() => {
    if (delay !== null) {
      const interval = setInterval(() => savedCallback.current(), delay || 0);
      return () => clearInterval(interval);
    }

    return undefined;
  }, [delay]);

  return [count, { startCountdown, stopCountdown, resetCountdown }];
}

import { useCallback, useState } from "react";

function useCounter(
  startingValue: number = 0,
  options: {
    min?: number;
    max?: number;
  } = {},
) {
  const { min, max } = options;

  if (typeof min === "number" && startingValue < min) {
    throw new Error(`Your starting value of ${startingValue} is less than your min of ${min}.`);
  }

  if (typeof max === "number" && startingValue > max) {
    throw new Error(`Your starting value of ${startingValue} is greater than your max of ${max}.`);
  }

  const [count, setCount] = useState(startingValue);

  const increment = useCallback(() => {
    setCount((c) => {
      const nextCount = c + 1;

      if (typeof max === "number" && nextCount > max) {
        return c;
      }

      return nextCount;
    });
  }, [max]);

  const decrement = useCallback(() => {
    setCount((c) => {
      const nextCount = c - 1;

      if (typeof min === "number" && nextCount < min) {
        return c;
      }

      return nextCount;
    });
  }, [min]);

  const set = useCallback(
    (nextCount: number) => {
      setCount((c) => {
        if (typeof max === "number" && nextCount > max) {
          return c;
        }

        if (typeof min === "number" && nextCount < min) {
          return c;
        }

        return nextCount;
      });
    },
    [max, min],
  );

  const reset = useCallback(() => {
    setCount(startingValue);
  }, [startingValue]);

  return [
    count,
    {
      increment,
      decrement,
      set,
      reset,
    },
  ];
}

export default useCounter;

import { useEffect, useState } from "react";

function useDebounce<T>(value: T, delay: number): T {
  const [debouncedValue, setDebouncedValue] = useState(value);

  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    return () => {
      clearTimeout(handler);
    };
  }, [value, delay]);

  return debouncedValue;
}

export default useDebounce;

import { useState } from "react";

function useDefault<T>(initialValue: T, defaultValue: T) {
  const [state, setState] = useState(initialValue);

  if (typeof state === "undefined" || state === null) {
    return [defaultValue, setState];
  }

  return [state, setState];
}

export default useDefault;

import { useEffect } from "react";

function useDocumentTitle(title: string) {
  useEffect(() => {
    document.title = title;
  }, [title]);
}

export default useDocumentTitle;

import type { RefObject } from "react";

import { useEffect, useRef } from "react";

function useEventListener<K extends keyof MediaQueryListEventMap>(
  eventName: K,
  handler: (event: MediaQueryListEventMap[K]) => void,
  element: RefObject<MediaQueryList>,
  options?: boolean | AddEventListenerOptions,
): void;

// Window Event based useEventListener interface
function useEventListener<K extends keyof WindowEventMap>(
  eventName: K,
  handler: (event: WindowEventMap[K]) => void,
  element?: undefined,
  options?: boolean | AddEventListenerOptions,
): void;

// Element Event based useEventListener interface
function useEventListener<
  K extends keyof HTMLElementEventMap & keyof SVGElementEventMap,
  T extends Element = K extends keyof HTMLElementEventMap ? HTMLDivElement : SVGElement,
>(
  eventName: K,
  handler: ((event: HTMLElementEventMap[K]) => void) | ((event: SVGElementEventMap[K]) => void),
  element: RefObject<T>,
  options?: boolean | AddEventListenerOptions,
): void;

// Document Event based useEventListener interface
function useEventListener<K extends keyof DocumentEventMap>(
  eventName: K,
  handler: (event: DocumentEventMap[K]) => void,
  element: RefObject<Document>,
  options?: boolean | AddEventListenerOptions,
): void;

function useEventListener<
  KW extends keyof WindowEventMap,
  KH extends keyof HTMLElementEventMap & keyof SVGElementEventMap,
  KM extends keyof MediaQueryListEventMap,
  T extends HTMLElement | SVGAElement | MediaQueryList = HTMLElement,
>(
  eventName: KW | KH | KM,
  handler: (event: WindowEventMap[KW] | HTMLElementEventMap[KH] | SVGElementEventMap[KH] | MediaQueryListEventMap[KM] | Event) => void,
  element?: RefObject<T>,
  options?: boolean | AddEventListenerOptions,
) {
  // Create a ref that stores handler
  const savedHandler = useRef(handler);

  useEffect(() => {
    savedHandler.current = handler;
  }, [handler]);

  useEffect(() => {
    // Define the listening target
    const targetElement: T | Window = element?.current ?? window;

    if (!(targetElement && targetElement.addEventListener))
      return;

    const listener: typeof handler = (event) => {
      savedHandler.current(event);
    };

    targetElement.addEventListener(eventName, listener, options);

    return () => {
      targetElement.removeEventListener(eventName, listener, options);
    };
  }, [eventName, element, options]);
}

export { useEventListener };

import { useEffect } from "react";

function useFavicon(url: string) {
  useEffect(() => {
    let link = document.querySelector<HTMLLinkElement>(`link[rel~="icon"]`);

    if (!link) {
      link = document.createElement("link");
      link.type = "image/x-icon";
      link.rel = "icon";
      link.href = url;
      document.head.appendChild(link);
    }
    else {
      link.href = url;
    }
  }, [url]);
}

export default useFavicon;

import { useEffect, useEffectEvent, useReducer, useRef } from "react";

type FetchState<T> = {
  data?: T;
  error?: Error;
};

type FetchAction<T> = { type: "loading" } | { type: "fetched"; payload: T } | { type: "error"; payload: Error };

const initialState: FetchState<unknown> = {
  data: undefined,
  error: undefined,
};

function fetchReducer<T>(state: FetchState<T>, action: FetchAction<T>): FetchState<T> {
  switch (action.type) {
    case "loading":
      return { data: undefined, error: undefined };

    case "fetched":
      return { data: action.payload, error: undefined };

    case "error":
      return { data: undefined, error: action.payload };

    default:
      return state;
  }
}

function useFetch<T = unknown>(url: string, options?: RequestInit): FetchState<T> {
  const cacheRef = useRef<Record<string, T>>({});

  const [state, dispatch] = useReducer(fetchReducer<T>, initialState as FetchState<T>);

  const onFetch = useEffectEvent((url: string) => {
    return fetch(url, options);
  });

  useEffect(() => {
    let ignore = false;

    const fetchData = async () => {
      const cached = cacheRef.current[url];

      if (cached) {
        dispatch({ type: "fetched", payload: cached });
        return;
      }

      dispatch({ type: "loading" });

      try {
        const res = await onFetch(url);

        if (!res.ok) {
          throw new Error(res.statusText);
        }

        const json = (await res.json()) as T;
        cacheRef.current[url] = json;

        if (!ignore) {
          dispatch({ type: "fetched", payload: json });
        }
      }
      catch (err) {
        if (!ignore) {
          dispatch({
            type: "error",
            payload: err instanceof Error ? err : new Error("Unknown error"),
          });
        }
      }
    };

    fetchData();

    return () => {
      ignore = true;
    };
  }, [url]);

  return state;
}

export default useFetch;

import { useEffect, useRef, useState } from "react";

type GeolocationState = {
  loading: boolean;
  accuracy: number | null;
  altitude: number | null;
  altitudeAccuracy: number | null;
  heading: number | null;
  latitude: number | null;
  longitude: number | null;
  speed: number | null;
  timestamp: number | null;
  error: GeolocationPositionError | null;
};

export function useGeolocation(options: PositionOptions = {}) {
  const [state, setState] = useState<GeolocationState>({
    loading: true,
    accuracy: null,
    altitude: null,
    altitudeAccuracy: null,
    heading: null,
    latitude: null,
    longitude: null,
    speed: null,
    timestamp: null,
    error: null,
  });

  const optionsRef = useRef<PositionOptions>(options);

  useEffect(() => {
    const onEvent = (position: GeolocationPosition) => {
      const { coords, timestamp } = position;

      setState({
        loading: false,
        timestamp,
        latitude: coords.latitude,
        longitude: coords.longitude,
        altitude: coords.altitude,
        accuracy: coords.accuracy,
        altitudeAccuracy: coords.altitudeAccuracy,
        heading: coords.heading,
        speed: coords.speed,
        error: null,
      });
    };

    const onEventError = (error: GeolocationPositionError) => {
      setState(s => ({
        ...s,
        loading: false,
        error,
      }));
    };

    navigator.geolocation.getCurrentPosition(onEvent, onEventError, optionsRef.current);

    const watchId = navigator.geolocation.watchPosition(onEvent, onEventError, optionsRef.current);

    return () => {
      navigator.geolocation.clearWatch(watchId);
    };
  }, []);

  return state;
}

import { useCallback, useReducer, useRef } from "react";

type HistoryStateType<T> = {
  past: T[];
  present: T;
  future: T[];
};

type HistoryAction<T> = { type: "UNDO" } | { type: "REDO" } | { type: "SET"; newPresent: T } | { type: "CLEAR"; initialPresent: T };

export type HistoryState<T> = {
  state: T;
  set: (newPresent: T) => void;
  undo: () => void;
  redo: () => void;
  clear: () => void;
  canUndo: boolean;
  canRedo: boolean;
};

function useHistoryStateReducer<T>(state: HistoryStateType<T>, action: HistoryAction<T>): HistoryStateType<T> {
  const { past, present, future } = state;
  switch (action.type) {
    case "UNDO":
      if (past.length === 0)
        return state;
      return {
        past: past.slice(0, past.length - 1),
        present: past[past.length - 1] as T,
        future: [present, ...future],
      };
    case "REDO":
      if (future.length === 0)
        return state;
      return {
        past: [...past, present],
        present: future[0] as T,
        future: future.slice(1),
      };
    case "SET":
      if (action.newPresent === present)
        return state;
      return {
        past: [...past, present],
        present: action.newPresent,
        future: [],
      };
    case "CLEAR":
      return {
        past: [],
        present: action.initialPresent,
        future: [],
      };
    default:
      throw new Error("Unsupported action type");
  }
}

function useHistoryState<T>(initialPresent: T): HistoryState<T> {
  const initialPresentRef = useRef(initialPresent);

  const [state, dispatch] = useReducer(useHistoryStateReducer<T>, initialPresent, present => ({ past: [], present, future: [] }));

  const canUndo = state.past.length > 0;
  const canRedo = state.future.length > 0;

  const undo = useCallback(() => {
    if (canUndo)
      dispatch({ type: "UNDO" });
  }, [canUndo]);

  const redo = useCallback(() => {
    if (canRedo)
      dispatch({ type: "REDO" });
  }, [canRedo]);

  const set = useCallback((newPresent: T) => dispatch({ type: "SET", newPresent }), []);

  const clear = useCallback(() => dispatch({ type: "CLEAR", initialPresent: initialPresentRef.current }), []);

  return { state: state.present, set, undo, redo, clear, canUndo, canRedo };
}

export default useHistoryState;

import { useCallback, useRef, useState } from "react";

export function useHover() {
  const [hovering, setHovering] = useState(false);
  const previousNode = useRef<HTMLElement | null>(null);

  const handleMouseEnter = useCallback(() => {
    setHovering(true);
  }, []);

  const handleMouseLeave = useCallback(() => {
    setHovering(false);
  }, []);

  const customRef = useCallback(
    (node: HTMLElement | null) => {
      if (previousNode.current?.nodeType === Node.ELEMENT_NODE) {
        previousNode.current.removeEventListener("mouseenter", handleMouseEnter);
        previousNode.current.removeEventListener("mouseleave", handleMouseLeave);
      }

      if (node?.nodeType === Node.ELEMENT_NODE) {
        node.addEventListener("mouseenter", handleMouseEnter);
        node.addEventListener("mouseleave", handleMouseLeave);
      }

      previousNode.current = node;
    },
    [handleMouseEnter, handleMouseLeave],
  );

  return [customRef, hovering];
}

import { useEffect, useState } from "react";

function throttle(callback: () => void, time: number = 200) {
  let lastTime = 0;
  return () => {
    const now = Date.now();
    if (now - lastTime >= time) {
      callback();
      lastTime = now;
    }
  };
}

function useIdle(ms: number = 1000 * 60) {
  const [idle, setIdle] = useState(false);

  useEffect(() => {
    let timeoutId: number | undefined;

    const handleTimeout = () => {
      setIdle(true);
    };

    const handleEvent = throttle(() => {
      setIdle(false);

      window.clearTimeout(timeoutId);
      timeoutId = window.setTimeout(handleTimeout, ms);
    }, 500);

    const handleVisibilityChange = () => {
      if (!document.hidden) {
        handleEvent();
      }
    };

    timeoutId = window.setTimeout(handleTimeout, ms);

    window.addEventListener("mousemove", handleEvent);
    window.addEventListener("mousedown", handleEvent);
    window.addEventListener("resize", handleEvent);
    window.addEventListener("keydown", handleEvent);
    window.addEventListener("touchstart", handleEvent);
    window.addEventListener("wheel", handleEvent);
    document.addEventListener("visibilitychange", handleVisibilityChange);

    return () => {
      window.removeEventListener("mousemove", handleEvent);
      window.removeEventListener("mousedown", handleEvent);
      window.removeEventListener("resize", handleEvent);
      window.removeEventListener("keydown", handleEvent);
      window.removeEventListener("touchstart", handleEvent);
      window.removeEventListener("wheel", handleEvent);
      document.removeEventListener("visibilitychange", handleVisibilityChange);
      window.clearTimeout(timeoutId);
    };
  }, [ms]);

  return idle;
}

export default useIdle;

import { useEffect, useRef, useState } from "react";

type UseInViewOptions = {
  threshold?: number | number[];
  root?: Element | null;
  rootMargin?: string;
  once?: boolean;
};

export function useInViewport(ref: React.RefObject<HTMLElement | null>, options: UseInViewOptions = {}): boolean {
  const { threshold = 0, root = null, rootMargin = "0px", once = false } = options;
  const [isInView, setIsInView] = useState(false);
  const observerRef = useRef<IntersectionObserver | null>(null);

  useEffect(() => {
    if (typeof window === "undefined" || !ref.current)
      return;

    observerRef.current = new IntersectionObserver(
      ([entry]) => {
        setIsInView(entry?.isIntersecting ?? false);
        if (entry?.isIntersecting && once) {
          observerRef.current?.unobserve(entry.target);
        }
      },
      { threshold, root, rootMargin },
    );

    observerRef.current.observe(ref.current);

    return () => {
      observerRef.current?.disconnect();
    };
  }, [root, rootMargin, threshold, once]);

  return isInView;
}

import { useCallback, useRef, useState } from "react";

function useIntersectionObserver<T extends Element>(options: IntersectionObserverInit) {
  const { threshold = 1, root = null, rootMargin = "0px" } = options;
  const [entry, setEntry] = useState<IntersectionObserverEntry>();

  const previousObserver = useRef<IntersectionObserver | null>(null);

  const customRef = useCallback(
    (node: T | null) => {
      if (previousObserver.current) {
        previousObserver.current.disconnect();
        previousObserver.current = null;
      }

      if (node?.nodeType === Node.ELEMENT_NODE) {
        const observer = new IntersectionObserver(
          ([entry]) => {
            setEntry(entry);
          },
          { threshold, root, rootMargin },
        );

        observer.observe(node);
        previousObserver.current = observer;
      }
    },
    [threshold, root, rootMargin],
  );

  return [customRef, entry] as const;
}

export default useIntersectionObserver;

import { useEffect, useEffectEvent, useRef } from "react";

function useInterval(cb: CallableFunction, delay: number) {
  const id = useRef<number | undefined>(undefined);
  const onInterval = useEffectEvent(cb);

  const handleClearInterval = () => {
    window.clearInterval(id.current);
  };

  useEffect(() => {
    id.current = window.setInterval(onInterval, delay);
    return handleClearInterval;
  }, [delay]);

  return handleClearInterval;
}

export default useInterval;

import { useSyncExternalStore } from "react";

const subscribe = () => () => {};

function useIsClient() {
  return useSyncExternalStore(
    subscribe,
    () => true, // client snapshot
    () => false, // server snapshot
  );
}

export default useIsClient;

import { useEffect, useRef, useState } from "react";

function useIsFirstRender() {
  const [isFirst, setIsFirst] = useState(true);
  const hasRenderedRef = useRef(false);

  useEffect(() => {
    if (!hasRenderedRef.current) {
      hasRenderedRef.current = true;
      setIsFirst(false);
    }
  }, []);

  return isFirst;
}

export default useIsFirstRender;

import { useSyncExternalStore } from "react";

const MOBILE_BREAKPOINT = 768;

function subscribe(callback: () => void) {
  const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`);
  mql.addEventListener("change", callback);
  return () => mql.removeEventListener("change", callback);
}

function getSnapshot() {
  return window.innerWidth < MOBILE_BREAKPOINT;
}

function useIsMobile() {
  return useSyncExternalStore(subscribe, getSnapshot, () => false);
}

export default useIsMobile;

import { useCallback, useEffect, useRef } from "react";

export function useIsMounted(): () => boolean {
  const isMounted = useRef(false);
  useEffect(() => {
    isMounted.current = true;
    return () => {
      isMounted.current = false;
    };
  }, []);

  return useCallback(() => isMounted.current, []);
}

import { useEffect, useEffectEvent } from "react";

type UseKeyPressOptions = {
  event?: keyof WindowEventMap;
  target?: Element | Window;
  eventOptions?: AddEventListenerOptions;
};

export function useKeyPress(key: string, cb: (event: KeyboardEvent) => void, options: UseKeyPressOptions = {}) {
  const { event = "keydown", target = window, eventOptions } = options;

  const onListen = useEffectEvent(() => {
    if (!target?.addEventListener)
      return;

    const handler = (e: KeyboardEvent) => {
      if (e.key === key) {
        cb(e);
      }
    };

    target.addEventListener(event, handler as EventListener, eventOptions);

    return () => {
      target.removeEventListener(event, handler as EventListener, eventOptions);
    };
  });

  useEffect(() => {
    const cleanup = onListen();
    return cleanup;
  }, [onListen]);
}

import { useCallback, useState } from "react";

function useList<T>(defaultList: T[] = []) {
  const [list, setList] = useState<T[]>(defaultList);

  const set = useCallback((l: T[]) => {
    setList(l);
  }, []);

  const push = useCallback((element: T) => {
    setList(l => [...l, element]);
  }, []);

  const removeAt = useCallback((index: number) => {
    setList(l => [...l.slice(0, index), ...l.slice(index + 1)]);
  }, []);

  const insertAt = useCallback((index: number, element: T) => {
    setList(l => [...l.slice(0, index), element, ...l.slice(index)]);
  }, []);

  const updateAt = useCallback((index: number, element: T) => {
    setList(l => l.map((e, i) => (i === index ? element : e)));
  }, []);

  const clear = useCallback(() => setList([]), []);

  return [list, { set, push, removeAt, insertAt, updateAt, clear }] as const;
}

