import { useMemo, useRef } from "react";

type LongPressOptions = {
  threshold?: number;
  onStart?: (e: MouseEvent | TouchEvent) => void;
  onFinish?: (e: MouseEvent | TouchEvent) => void;
  onCancel?: (e: MouseEvent | TouchEvent) => void;
};

type LongPressEventHandlers = {
  onMouseDown: (e: MouseEvent) => void;
  onMouseUp: (e: MouseEvent) => void;
  onMouseLeave: (e: MouseEvent) => void;
  onTouchStart: (e: TouchEvent) => void;
  onTouchEnd: (e: TouchEvent) => void;
};

function isMouseEvent(e: Event): e is MouseEvent {
  return "button" in e;
}

function isTouchEvent(e: Event): e is TouchEvent {
  return "touches" in e;
}

function useLongPress(callback: (e: MouseEvent | TouchEvent) => void, options: LongPressOptions = {}): LongPressEventHandlers {
  const { threshold = 400, onStart, onFinish, onCancel } = options;

  const isLongPressActive = useRef(false);
  const isPressed = useRef(false);
  const timerId = useRef<number | undefined>(undefined);

  return useMemo(() => {
    if (typeof callback !== "function") {
      throw new TypeError("Callback must be a function");
    }

    const start = (event: MouseEvent | TouchEvent) => {
      if (!isMouseEvent(event) && !isTouchEvent(event))
        return;

      if (onStart)
        onStart(event);

      isPressed.current = true;
      timerId.current = window.setTimeout(() => {
        callback(event);
        isLongPressActive.current = true;
      }, threshold);
    };

    const cancel = (event: MouseEvent | TouchEvent) => {
      if (!isMouseEvent(event) && !isTouchEvent(event))
        return;

      if (isLongPressActive.current) {
        if (onFinish)
          onFinish(event);
      }
      else if (isPressed.current) {
        if (onCancel)
          onCancel(event);
      }

      isLongPressActive.current = false;
      isPressed.current = false;

      if (timerId.current !== undefined) {
        window.clearTimeout(timerId.current);
        timerId.current = undefined;
      }
    };

    return {
      onMouseDown: start,
      onMouseUp: cancel,
      onMouseLeave: cancel,
      onTouchStart: start,
      onTouchEnd: cancel,
    };
  }, [callback, threshold, onCancel, onFinish, onStart]);
}

export default useLongPress;
export type { LongPressEventHandlers, LongPressOptions };

import { useCallback, useState } from "react";

type MapOrEntries<K, V> = Map<K, V> | [K, V][];

type UseMapActions<K, V> = {
  set: (key: K, value: V) => void;
  setAll: (entries: MapOrEntries<K, V>) => void;
  remove: (key: K) => void;
  reset: Map<K, V>["clear"];
};

type UseMapReturn<K, V> = [Omit<Map<K, V>, "set" | "clear" | "delete">, UseMapActions<K, V>];

function useMap<K, V>(initialState: MapOrEntries<K, V> = new Map()): UseMapReturn<K, V> {
  const [map, setMap] = useState(new Map(initialState));

  const actions: UseMapActions<K, V> = {
    set: useCallback((key, value) => {
      setMap((prev) => {
        const copy = new Map(prev);
        copy.set(key, value);
        return copy;
      });
    }, []),

    setAll: useCallback((entries) => {
      setMap(() => new Map(entries));
    }, []),

    remove: useCallback((key) => {
      setMap((prev) => {
        const copy = new Map(prev);
        copy.delete(key);
        return copy;
      });
    }, []),

    reset: useCallback(() => {
      setMap(() => new Map());
    }, []),
  };

  return [map, actions];
}

export default useMap;

import { useCallback, useRef, useState } from "react";

type Size = {
  width: number | null;
  height: number | null;
};

function useMeasure() {
  const [dimensions, setDimensions] = useState<Size>({
    width: null,
    height: null,
  });

  const observerRef = useRef<ResizeObserver | null>(null);

  const customRef = useCallback((node: Element | null) => {
    if (observerRef.current) {
      observerRef.current.disconnect();
      observerRef.current = null;
    }

    if (!node)
      return;

    const observer = new ResizeObserver(([entry]) => {
      if (!entry)
        return;

      const boxSize = Array.isArray(entry.borderBoxSize) ? entry.borderBoxSize[0] : entry.borderBoxSize;

      const width = boxSize?.inlineSize ?? entry.contentRect.width;

      const height = boxSize?.blockSize ?? entry.contentRect.height;

      setDimensions({ width, height });
    });

    observer.observe(node);
    observerRef.current = observer;
  }, []);

  return [customRef, dimensions] as const;
}

export default useMeasure;

