import { useLayoutEffect, useRef, useState } from "react";

type MouseState = {
  x: number;
  y: number;
  elementX: number;
  elementY: number;
  elementPositionX: number;
  elementPositionY: number;
};

function useMouse<T extends HTMLElement = HTMLElement>() {
  const [state, setState] = useState<MouseState>({
    x: 0,
    y: 0,
    elementX: 0,
    elementY: 0,
    elementPositionX: 0,
    elementPositionY: 0,
  });

  const ref = useRef<T | null>(null);

  useLayoutEffect(() => {
    const handleMouseMove = (event: MouseEvent) => {
      const next: Partial<MouseState> = {
        x: event.pageX,
        y: event.pageY,
      };

      if (ref.current) {
        const { left, top } = ref.current.getBoundingClientRect();
        const elementPositionX = left + window.scrollX;
        const elementPositionY = top + window.scrollY;

        next.elementX = event.pageX - elementPositionX;
        next.elementY = event.pageY - elementPositionY;
        next.elementPositionX = elementPositionX;
        next.elementPositionY = elementPositionY;
      }

      setState(prev => ({ ...prev, ...next }));
    };

    document.addEventListener("mousemove", handleMouseMove);
    return () => document.removeEventListener("mousemove", handleMouseMove);
  }, []);

  return [state, ref] as const;
}

export default useMouse;

import { useRef, useSyncExternalStore } from "react";

type NetworkInformation = {
  downlink?: number;
  downlinkMax?: number;
  effectiveType?: string;
  rtt?: number;
  saveData?: boolean;
  type?: string;
  addEventListener: (type: "change", listener: EventListener) => void;
  removeEventListener: (type: "change", listener: EventListener) => void;
};

type NetworkState = {
  online: boolean;
  downlink?: number;
  downlinkMax?: number;
  effectiveType?: string;
  rtt?: number;
  saveData?: boolean;
  type?: string;
};

declare global {
  interface Navigator {
    connection?: NetworkInformation;
    mozConnection?: NetworkInformation;
    webkitConnection?: NetworkInformation;
  }
}

function getConnection(): NetworkInformation | undefined {
  return navigator?.connection || navigator?.mozConnection || navigator?.webkitConnection;
}

function isShallowEqual<T extends object>(a: T, b: T) {
  if (Object.is(a, b))
    return true;

  const aKeys = Object.keys(a) as (keyof T)[];
  const bKeys = Object.keys(b) as (keyof T)[];

  if (aKeys.length !== bKeys.length)
    return false;

  for (const key of aKeys) {
    if (!Object.is(a[key], b[key]))
      return false;
  }

  return true;
}

function useNetworkStateSubscribe(onStoreChange: () => void) {
  const handler = () => onStoreChange();

  window.addEventListener("online", handler, { passive: true });
  window.addEventListener("offline", handler, { passive: true });

  const connection = getConnection();
  if (connection) {
    connection.addEventListener("change", handler);
  }

  return () => {
    window.removeEventListener("online", handler);
    window.removeEventListener("offline", handler);

    if (connection) {
      connection.removeEventListener("change", handler);
    }
  };
}

function getNetworkStateServerSnapshot(): never {
  throw new Error("useNetworkState is a client-only hook");
}

export function useNetworkState(): NetworkState {
  const cache = useRef<NetworkState | null>(null);

  const getSnapshot = (): NetworkState => {
    const online = navigator.onLine;
    const connection = getConnection();

    const nextState: NetworkState = {
      online,
      downlink: connection?.downlink,
      downlinkMax: connection?.downlinkMax,
      effectiveType: connection?.effectiveType,
      rtt: connection?.rtt,
      saveData: connection?.saveData,
      type: connection?.type,
    };

    if (cache.current && isShallowEqual(cache.current, nextState)) {
      return cache.current;
    }

    cache.current = nextState;
    return nextState;
  };

  return useSyncExternalStore(useNetworkStateSubscribe, getSnapshot, getNetworkStateServerSnapshot);
}

