import type { RefObject } from "react";

import { useEffect, useRef, useState } from "react";

import { useIsMounted } from "./use-is-mounted";

type Size = {
  width: number | undefined;
  height: number | undefined;
};

type UseResizeObserverOptions<T extends HTMLElement = HTMLElement> = {
  ref: RefObject<T | null>;
  onResize?: (size: Size) => void;
  box?: "border-box" | "content-box" | "device-pixel-content-box";
};

const initialSize: Size = {
  width: undefined,
  height: undefined,
};

export function useResizeObserver<T extends HTMLElement = HTMLElement>(options: UseResizeObserverOptions<T>): Size {
  const { ref, box = "content-box" } = options;
  const [{ width, height }, setSize] = useState<Size>(initialSize);
  const isMounted = useIsMounted();
  const previousSize = useRef<Size>({ ...initialSize });
  const onResize = useRef<((size: Size) => void) | undefined>(undefined);
  useEffect(() => {
    onResize.current = options.onResize;
  }, [options.onResize]);

  useEffect(() => {
    if (!ref?.current)
      return;

    if (typeof window === "undefined" || !("ResizeObserver" in window))
      return;

    const observer = new ResizeObserver(([entry]) => {
      const boxProp
        = box === "border-box" ? "borderBoxSize" : box === "device-pixel-content-box" ? "devicePixelContentBoxSize" : "contentBoxSize";

      const newWidth = extractSize(entry!, boxProp, "inlineSize");
      const newHeight = extractSize(entry!, boxProp, "blockSize");

      const hasChanged = previousSize.current.width !== newWidth || previousSize.current.height !== newHeight;

      if (hasChanged) {
        const newSize: Size = { width: newWidth, height: newHeight };
        previousSize.current.width = newWidth;
        previousSize.current.height = newHeight;

        if (onResize.current) {
          onResize.current(newSize);
        }
        else {
          if (isMounted()) {
            setSize(newSize);
          }
        }
      }
    });

    observer.observe(ref.current, { box });

    return () => {
      observer.disconnect();
    };
  }, [box, ref, isMounted]);

  return { width, height };
}

type BoxSizesKey = keyof Pick<ResizeObserverEntry, "borderBoxSize" | "contentBoxSize" | "devicePixelContentBoxSize">;

function extractSize(entry: ResizeObserverEntry, box: BoxSizesKey, sizeType: keyof ResizeObserverSize): number | undefined {
  if (!entry[box]) {
    if (box === "contentBoxSize") {
      return entry.contentRect[sizeType === "inlineSize" ? "width" : "height"];
    }
    return undefined;
  }

  return Array.isArray(entry[box])
    ? entry[box][0][sizeType]
    : // @ts-expect-error Support Firefox's non-standard behavior
      (entry[box][sizeType] as number);
}

import { useEffect, useState } from "react";

type UseScriptStatus = "idle" | "loading" | "ready" | "error";

type UseScriptOptions = {
  shouldPreventLoad?: boolean;
  removeOnUnmount?: boolean;
  id?: string;
};

const cachedScriptStatuses = new Map<string, UseScriptStatus | undefined>();

function getScriptNode(src: string) {
  const node: HTMLScriptElement | null = document.querySelector(`script[src="${src}"]`);
  const status = node?.getAttribute("data-status") as UseScriptStatus | undefined;

  return {
    node,
    status,
  };
}

function useScript(src: string | null, options?: UseScriptOptions): UseScriptStatus {
  const [status, setStatus] = useState<UseScriptStatus>(() => {
    if (!src || options?.shouldPreventLoad) {
      return "idle";
    }

    if (typeof window === "undefined") {
      // SSR Handling - always return 'loading'
      return "loading";
    }

    return cachedScriptStatuses.get(src) ?? "loading";
  });

  useEffect(() => {
    if (!src || options?.shouldPreventLoad) {
      return;
    }

    const cachedScriptStatus = cachedScriptStatuses.get(src);
    if (cachedScriptStatus === "ready" || cachedScriptStatus === "error") {
      // If the script is already cached, set its status immediately
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setStatus(cachedScriptStatus);
      return;
    }

    // Fetch existing script element by src
    // It may have been added by another instance of this hook
    const script = getScriptNode(src);
    let scriptNode = script.node;

    if (!scriptNode) {
      // Create script element and add it to document body
      scriptNode = document.createElement("script");
      scriptNode.src = src;
      scriptNode.async = true;
      if (options?.id) {
        scriptNode.id = options.id;
      }
      scriptNode.setAttribute("data-status", "loading");
      document.body.appendChild(scriptNode);

      // Store status in attribute on script
      // This can be read by other instances of this hook
      const setAttributeFromEvent = (event: Event) => {
        const scriptStatus: UseScriptStatus = event.type === "load" ? "ready" : "error";

        scriptNode?.setAttribute("data-status", scriptStatus);
      };

      scriptNode.addEventListener("load", setAttributeFromEvent);
      scriptNode.addEventListener("error", setAttributeFromEvent);
    }
    else {
      // Grab existing script status from attribute and set to state.
      setStatus(script.status ?? cachedScriptStatus ?? "loading");
    }

    // Script event handler to update status in state
    // Note: Even if the script already exists we still need to add
    // event handlers to update the state for *this* hook instance.
    const setStateFromEvent = (event: Event) => {
      const newStatus = event.type === "load" ? "ready" : "error";
      setStatus(newStatus);
      cachedScriptStatuses.set(src, newStatus);
    };

    // Add event listeners
    scriptNode.addEventListener("load", setStateFromEvent);
    scriptNode.addEventListener("error", setStateFromEvent);

    // Remove event listeners on cleanup
    return () => {
      if (scriptNode) {
        scriptNode.removeEventListener("load", setStateFromEvent);
        scriptNode.removeEventListener("error", setStateFromEvent);
      }

      if (scriptNode && options?.removeOnUnmount) {
        scriptNode.remove();
        cachedScriptStatuses.delete(src);
      }
    };
  }, [src, options?.shouldPreventLoad, options?.removeOnUnmount, options?.id]);

  return status;
}

export default useScript;

import { useCallback, useEffect, useSyncExternalStore } from "react";

type ValueType = string | null | undefined;

function dispatchStorageEvent(key: string, newValue: ValueType = null) {
  window.dispatchEvent(new StorageEvent("storage", { key, newValue }));
}

function setSessionStorageItem<T>(key: string, value: T) {
  const stringifiedValue = JSON.stringify(value);
  window.sessionStorage.setItem(key, stringifiedValue);
  dispatchStorageEvent(key, stringifiedValue);
}

function removeSessionStorageItem(key: string) {
  window.sessionStorage.removeItem(key);
  dispatchStorageEvent(key, null);
}

function getSessionStorageItem(key: string) {
  return window.sessionStorage.getItem(key);
}

function useSessionStorageSubscribe(
  callback: EventListenerOrEventListenerObject,
) {
  window.addEventListener("storage", callback);
  return () => window.removeEventListener("storage", callback);
}

function getSessionStorageServerSnapshot(): string | null {
  throw new Error("useSessionStorage is a client-only hook");
}

type SetValue<T> = T | ((prevState: T) => T);

function useSessionStorage<T>(
  key: string,
  initialValue: T,
): [T, (v: SetValue<T>) => void] {
  const getSnapshot = () => getSessionStorageItem(key);

  const store = useSyncExternalStore(
    useSessionStorageSubscribe,
    getSnapshot,
    getSessionStorageServerSnapshot,
  );

  const setState = useCallback(
    (v: SetValue<T>) => {
      try {
        const currentState = store ? JSON.parse(store) : initialValue;
        const nextState
          = typeof v === "function"
            ? (v as (prevState: T) => T)(currentState)
            : v;

        if (nextState === undefined || nextState === null) {
          removeSessionStorageItem(key);
        }
        else {
          setSessionStorageItem(key, nextState);
        }
      }
      catch (e) {
        console.warn(e);
      }
    },
    [key, store, initialValue],
  );

  useEffect(() => {
    if (
      getSessionStorageItem(key) === null
      && typeof initialValue !== "undefined"
    ) {
      setSessionStorageItem(key, initialValue);
    }
  }, [key, initialValue]);

  return [store ? JSON.parse(store) : initialValue, setState];
}

export default useSessionStorage;

import { useState } from "react";

function useSet<T>(values?: T[]) {
  const [set, setSet] = useState(() => new Set(values));

  function add(...args: T[]) {
    setSet(new Set([...set, ...args]));
  }

  function clear() {
    setSet(new Set());
  }

  function deleteItem(...args: T[]) {
    setSet(new Set([...set].filter(x => !args.includes(x))));
  }

  function hasItem(item: T) {
    return set.has(item);
  }

  return {
    add,
    clear,
    deleteItem,
    hasItem,
  };
}

export default useSet;

import type { HowlOptions } from "howler";

import { Howl } from "howler";
import { useCallback, useEffect, useRef, useState } from "react";

export type SpriteMap = Record<string, [number, number]>;

export type UseSoundOptions<T extends SpriteMap | undefined = undefined> = {
  volume?: number;
  playbackRate?: number;
  interrupt?: boolean;
  soundEnabled?: boolean;
  sprite?: T;
  onload?: (howl: Howl) => void;
} & Omit<HowlOptions, "src" | "sprite" | "onload">;

export type PlayOptions<T extends SpriteMap | undefined = undefined> = {
  forceSoundEnabled?: boolean;
  playbackRate?: number;
  id?: T extends SpriteMap ? keyof T : never;
};

export type SoundControls = {
  stop: (id?: number) => void;
  pause: (id?: number) => void;
  duration: number | null;
  sound: Howl | null;
  isLoading: boolean;
  isLoaded: boolean;
};

export type UseSoundReturn<T extends SpriteMap | undefined = undefined> = [(options?: PlayOptions<T>) => void, SoundControls];

export function useSound<T extends SpriteMap | undefined = undefined>(url: string, opts: UseSoundOptions<T> = {}): UseSoundReturn<T> {
  const { volume = 1, playbackRate = 1, interrupt = false, soundEnabled = true, sprite, onload, ...howlDelegated } = opts;

  const howlRef = useRef<Howl | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isLoaded, setIsLoaded] = useState(false);
  const [duration, setDuration] = useState<number | null>(null);

  const optsRef = useRef({ volume, playbackRate, interrupt, soundEnabled });
  useEffect(() => {
    optsRef.current = { volume, playbackRate, interrupt, soundEnabled };
  });

  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setIsLoading(true);
    setIsLoaded(false);
    setDuration(null);

    const howlOptions: HowlOptions = {
      src: [url],
      volume,
      rate: playbackRate,
      sprite: sprite as HowlOptions["sprite"],
      onload() {
        const howl = howlRef.current;
        if (!howl)
          return;
        setIsLoading(false);
        setIsLoaded(true);
        setDuration(howl.duration() * 1000);
        onload?.(howl);
      },
      onloaderror(_id, err) {
        setIsLoading(false);
        console.error(`[useSound] Failed to load "${url}":`, err);
      },
      ...howlDelegated,
    };

    howlRef.current = new Howl(howlOptions);

    return () => {
      howlRef.current?.unload();
    };
  }, [howlDelegated, onload, playbackRate, sprite, url, volume]);

  useEffect(() => {
    howlRef.current?.volume(volume);
  }, [volume]);

  useEffect(() => {
    howlRef.current?.rate(playbackRate);
  }, [playbackRate]);

  const play = useCallback((playOpts: PlayOptions<T> = {}) => {
    const { forceSoundEnabled = false, playbackRate: callPlaybackRate, id } = playOpts;

    const { soundEnabled, interrupt, volume } = optsRef.current;

    if (!forceSoundEnabled && !soundEnabled)
      return;

    const howl = howlRef.current;
    if (!howl)
      return;

    if (callPlaybackRate !== undefined) {
      howl.rate(callPlaybackRate);
    }

    if (interrupt) {
      howl.stop();
    }

    if (id) {
      howl.play(id as string);
    }
    else {
      howl.volume(volume);
      howl.play();
    }
  }, []);

  const stop = useCallback((id?: number) => {
    howlRef.current?.stop(id);
  }, []);

  const pause = useCallback((id?: number) => {
    howlRef.current?.pause(id);
  }, []);

  const controls: SoundControls = {
    stop,
    pause,
    duration,
    // eslint-disable-next-line react-hooks/refs
    sound: howlRef.current,
    isLoading,
    isLoaded,
  };

  return [play, controls];
}

export type LazySoundControls = {
  preload: () => void;
} & SoundControls;

export type UseSoundLazyReturn<T extends SpriteMap | undefined = undefined> = [(options?: PlayOptions<T>) => void, LazySoundControls];

export function useSoundLazy<T extends SpriteMap | undefined = undefined>(
  url: string,
  opts: UseSoundOptions<T> = {},
): UseSoundLazyReturn<T> {
  const [play, controls] = useSound<T>(url, {
    ...opts,
    preload: false,
  } as UseSoundOptions<T>);

  const preload = useCallback(() => {
    controls.sound?.load();
  }, [controls.sound]);

  return [play, { ...controls, preload }];
}

import type { Dispatch, SetStateAction } from "react";

import { useCallback, useState } from "react";

type UseStepActions = {
  goToNextStep: () => void;
  goToPrevStep: () => void;
  reset: () => void;
  canGoToNextStep: boolean;
  canGoToPrevStep: boolean;
  setStep: Dispatch<SetStateAction<number>>;
};

type SetStepCallbackType = (step: number | ((step: number) => number)) => void;

function useStep(maxStep: number): [number, UseStepActions] {
  const [currentStep, setCurrentStep] = useState(1);

  const canGoToNextStep = currentStep + 1 <= maxStep;
  const canGoToPrevStep = currentStep - 1 > 0;

  const setStep = useCallback<SetStepCallbackType>(
    (step) => {
      // Allow value to be a function so we have the same API as useState
      const newStep = typeof step === "function" ? step(currentStep) : step;

      if (newStep >= 1 && newStep <= maxStep) {
        setCurrentStep(newStep);
        return;
      }

      throw new Error("Step not valid");
    },
    [maxStep, currentStep],
  );

  const goToNextStep = useCallback(() => {
    if (canGoToNextStep) {
      setCurrentStep(step => step + 1);
    }
  }, [canGoToNextStep]);

  const goToPrevStep = useCallback(() => {
    if (canGoToPrevStep) {
      setCurrentStep(step => step - 1);
    }
  }, [canGoToPrevStep]);

  const reset = useCallback(() => {
    setCurrentStep(1);
  }, []);

  return [
    currentStep,
    {
      goToNextStep,
      goToPrevStep,
      canGoToNextStep,
      canGoToPrevStep,
      setStep,
      reset,
    },
  ];
}

export default useStep;

import { useEffect, useRef, useState } from "react";

function useThrottle<T>(value: T, interval: number = 500) {
  const [throttledValue, setThrottledValue] = useState(value);
  const lastUpdated = useRef<number | null>(null);

  useEffect(() => {
    const now = Date.now();

    if (lastUpdated.current && now >= lastUpdated.current + interval) {
      lastUpdated.current = now;
      setThrottledValue(value);
    }
    else {
      const id = window.setTimeout(() => {
        lastUpdated.current = now;
        setThrottledValue(value);
      }, interval);

      return () => window.clearTimeout(id);
    }
  }, [value, interval]);

  return throttledValue;
}

export default useThrottle;

import { useEffect, useRef } from "react";

function useTimeout(callback: () => void, delay: number | null): void {
  const savedCallback = useRef(callback);

  useEffect(() => {
    savedCallback.current = callback;
  }, [callback]);

  useEffect(() => {
    if (!delay && delay !== 0) {
      return;
    }

    const id = setTimeout(() => {
      savedCallback.current();
    }, delay);

    return () => {
      clearTimeout(id);
    };
  }, [delay]);
}

export default useTimeout;

import { useCallback, useState } from "react";

function useToggle(initialValue: boolean) {
  const [on, setOn] = useState(() => {
    if (typeof initialValue === "boolean") {
      return initialValue;
    }

    return Boolean(initialValue);
  });

  const handleToggle = useCallback((value?: boolean) => {
    if (typeof value === "boolean") {
      return setOn(value);
    }

    return setOn(v => !v);
  }, []);

  return [on, handleToggle];
}

export default useToggle;

import { useSyncExternalStore } from "react";

function useVisibilityChangeSubscribe(callback: (event: Event) => void) {
  document.addEventListener("visibilitychange", callback);

  return () => {
    document.removeEventListener("visibilitychange", callback);
  };
}

function getVisibilityChangeSnapshot() {
  return document.visibilityState;
}

function getVisibilityChangeServerSnapshot(): string {
  throw new Error("useVisibilityChange is a client-only hook");
}

function useVisibilityChange() {
  const visibilityState = useSyncExternalStore(
    useVisibilityChangeSubscribe,
    getVisibilityChangeSnapshot,
    getVisibilityChangeServerSnapshot,
  );

  return visibilityState === "visible";
}

export default useVisibilityChange;

import { useCallback, useLayoutEffect, useState } from "react";

function useWindowScroll() {
  const [state, setState] = useState<Readonly<{ x: number | null; y: number | null }>>({
    x: null,
    y: null,
  });

  const scrollTo = useCallback((...args: [ScrollToOptions] | [number, number]) => {
    if (typeof args[0] === "object") {
      window.scrollTo(args[0]);
    }
    else if (typeof args[0] === "number" && typeof args[1] === "number") {
      window.scrollTo(args[0], args[1]);
    }
    else {
      throw new TypeError(
        `Invalid arguments passed to scrollTo. See here for more info. https://developer.mozilla.org/en-US/docs/Web/API/Window/scrollTo`,
      );
    }
  }, []);

  useLayoutEffect(() => {
    const handleScroll = () => {
      setState({ x: window.scrollX, y: window.scrollY });
    };

    handleScroll();
    window.addEventListener("scroll", handleScroll);

    return () => {
      window.removeEventListener("scroll", handleScroll);
    };
  }, []);

  return [state, scrollTo] as const;
}

export default useWindowScroll;

import { useLayoutEffect, useState } from "react";

function useWindowSize() {
  const [size, setSize] = useState<Readonly<{ width: number | null; height: number | null }>>({
