    window.addEventListener("resize", handleResize);

    return () => {
      window.removeEventListener("resize", handleResize);
    };
  }, []);

  return size;
}

export default useWindowSize;

import { useCallback, useSyncExternalStore } from "react";

export type UseActiveElementOptions = {
  /**
   * Whether to resolve the deepest focused node inside open shadow roots.
   * @default true
   */
  deep?: boolean;
  /**
   * Whether to re-check active element when DOM nodes are removed.
   * @default false
   */
  triggerOnRemoval?: boolean;
};

function resolveActiveElement(deep: boolean): Element | null {
  if (typeof document === "undefined") {
    return null;
  }

  let activeElement: Element | null = document.activeElement;

  if (!deep) {
    return activeElement;
  }

  while (activeElement?.shadowRoot?.activeElement) {
    activeElement = activeElement.shadowRoot.activeElement;
  }

  return activeElement;
}

export function useActiveElement<T extends Element = HTMLElement>(
  options: UseActiveElementOptions = {},
): T | null {
  const { deep = true, triggerOnRemoval = false } = options;

  const subscribe = useCallback(
    (onStoreChange: () => void) => {
      if (typeof window === "undefined") {
        return () => {};
      }

      const onFocus = () => {
        onStoreChange();
      };
      const onBlur = (event: FocusEvent) => {
        if (event.relatedTarget !== null) {
          return;
        }
        onStoreChange();
      };

      window.addEventListener("focus", onFocus, true);
      window.addEventListener("blur", onBlur, true);

      const observer
        = triggerOnRemoval && typeof MutationObserver !== "undefined"
          ? new MutationObserver(() => {
              onStoreChange();
            })
          : null;

      observer?.observe(document, {
        childList: true,
        subtree: true,
      });

      return () => {
        window.removeEventListener("focus", onFocus, true);
        window.removeEventListener("blur", onBlur, true);
        observer?.disconnect();
      };
    },
    [triggerOnRemoval],
  );

  const getSnapshot = useCallback(() => {
    return resolveActiveElement(deep) as T | null;
  }, [deep]);

  const getServerSnapshot = useCallback(() => {
    return null as T | null;
  }, []);

  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

import { useCallback, useEffect } from "react";

function useBeforeUnload(enabled: boolean | (() => boolean) = true, message?: string) {
  const handler = useCallback(
    (event: BeforeUnloadEvent) => {
      const finalEnabled = typeof enabled === "function" ? enabled() : true;

      if (!finalEnabled) {
        return;
      }

      event.preventDefault();

      if (message) {
        event.returnValue = message;
      }

      return message;
    },
    [enabled, message],
  );

  useEffect(() => {
    if (!enabled) {
      return;
    }

    window.addEventListener("beforeunload", handler);

    return () => window.removeEventListener("beforeunload", handler);
  }, [enabled, handler]);
}

export default useBeforeUnload;

import { useEffect, useMemo, useRef } from "react";

function useCallbackRef<A extends unknown[], R>(callback?: (...args: A) => R) {
  const callbackRef = useRef(callback);
  useEffect(() => {
    callbackRef.current = callback;
  });
  return useMemo(
    () =>
      (...args: A) =>
        callbackRef.current?.(...args),
    [],
  );
}
export default useCallbackRef;

import type { RefObject } from "react";

import { useEffect, useRef } from "react";

const defaultEvents = ["mousedown", "touchstart"];

type UseClickAwayOptions<EventType extends Event = Event> = {
  ref: RefObject<HTMLElement | null>;
  onClickAway: (event: EventType) => void;
  events?: string[];
};

function useClickOutside<EventType extends Event = Event>({ ref, onClickAway, events = defaultEvents }: UseClickAwayOptions<EventType>) {
  const savedCallback = useRef(onClickAway);

  useEffect(() => {
    savedCallback.current = onClickAway;
  }, [onClickAway]);

  useEffect(() => {
    const handler = (event: EventType) => {
      const target = event.target as Node;
      if (ref.current && !ref.current.contains(target)) {
        savedCallback.current(event);
      }
    };
    for (const eventName of events) {
      window.addEventListener(eventName, handler as EventListener);
    }
    return () => {
      for (const eventName of events) {
        window.removeEventListener(eventName, handler as EventListener);
      }
    };
  }, [events, ref]);
}

export default useClickOutside;

import { useCallback } from "react";

type PossibleRef<T> = React.Ref<T> | undefined;

/**
 * Set a given ref to a given value
 * This utility takes care of different types of refs: callback refs and RefObject(s)
 */
function setRef<T>(ref: PossibleRef<T>, value: T) {
  if (typeof ref === "function") {
    return ref(value);
  }

  if (ref !== null && ref !== undefined) {
    ref.current = value;
  }
}

/**
 * A utility to compose multiple refs together
 * Accepts callback refs and RefObject(s)
 */
function composeRefs<T>(...refs: PossibleRef<T>[]): React.RefCallback<T> {
  return (node) => {
    let hasCleanup = false;
    const cleanups = refs.map((ref) => {
      const cleanup = setRef(ref, node);
      if (!hasCleanup && typeof cleanup === "function") {
        hasCleanup = true;
      }
      return cleanup;
    });

    // React <19 will log an error to the console if a callback ref returns a
    // value. We don't use ref cleanups internally so this will only happen if a
    // user's ref callback returns a value, which we only expect if they are
    // using the cleanup functionality added in React 19.
    if (hasCleanup) {
      return () => {
        for (let i = 0; i < cleanups.length; i++) {
          const cleanup = cleanups[i];
          if (typeof cleanup === "function") {
            cleanup();
          }
          else {
            setRef(refs[i], null);
          }
        }
      };
    }
  };
}

function useComposedRefs<T>(...refs: PossibleRef<T>[]): React.RefCallback<T> {
  // biome-ignore lint/correctness/useExhaustiveDependencies: we want to memoize by all values
  // eslint-disable-next-line react-hooks/exhaustive-deps, react-hooks/use-memo
  return useCallback(composeRefs(...refs), refs);
}

export { composeRefs, useComposedRefs };

import { useEffect, useState } from "react";

export type deviceType = "Mobile" | "Tablet" | "Desktop";

export type DeviceState = {
  isSupported: boolean;
  deviceType: deviceType;
  isMobile: boolean;
  isTablet: boolean;
  isDesktop: boolean;
};

/**
 * React hook that returns the type of device the code is running on.
 * @returns {DeviceState} The type of device the code is running on.
 */

export function useDetectDevice(): DeviceState {
  const [deviceState, setDeviceState] = useState<DeviceState>({
    isSupported: true,
    deviceType: "Desktop",
    isMobile: false,
    isTablet: false,
    isDesktop: true,
  });

  useEffect(() => {
    const handleDeviceDetection = () => {
      if (typeof navigator === "undefined") {
        setDeviceState(prevState => ({
          ...prevState,
          isSupported: false,
        }));
        return;
      }

      const userAgent = navigator.userAgent.toLowerCase();
      const isMobile = /iphone|ipad|ipod|android|blackberry|windows phone/.test(userAgent);
      const isTablet = /(ipad|tablet|playbook|silk)|(android(?!.*mobile))/.test(userAgent);

      if (isMobile) {
        setDeviceState({
          isSupported: true,
          deviceType: "Mobile",
          isMobile: true,
          isTablet: false,
          isDesktop: false,
        });
      }
      else if (isTablet) {
        setDeviceState({
          isSupported: true,
          deviceType: "Tablet",
          isMobile: false,
          isTablet: true,
          isDesktop: false,
        });
      }
      else {
        setDeviceState({
          isSupported: true,
          deviceType: "Desktop",
          isMobile: false,
          isTablet: false,
          isDesktop: true,
        });
      }
    };

    handleDeviceDetection();
    window.addEventListener("resize", handleDeviceDetection);
    return () => {
      window.removeEventListener("resize", handleDeviceDetection);
    };
  }, []);

  return deviceState;
}

import { useEffect, useState } from "react";

function useDocumentVisibility(): DocumentVisibilityState {
  const [documentVisibility, setDocumentVisibility] = useState<DocumentVisibilityState>(() =>
    typeof document === "undefined" ? "visible" : document.visibilityState,
  );

  useEffect(() => {
    const listener = () => setDocumentVisibility(document.visibilityState);
    document.addEventListener("visibilitychange", listener);
    return () => document.removeEventListener("visibilitychange", listener);
  }, []);

  return documentVisibility;
}

export default useDocumentVisibility;

"use client";

import type { ChangeEvent, DragEvent, InputHTMLAttributes } from "react";

import { useCallback, useRef, useState } from "react";

export type FileMetadata = {
  name: string;
  size: number;
  type: string;
  url: string;
  id: string;
};

export type FileWithPreview = {
  file: File | FileMetadata;
  id: string;
  preview?: string;
};

export type FileUploadOptions = {
  maxFiles?: number; // Only used when multiple is true, defaults to Infinity
  maxSize?: number; // in bytes
  accept?: string;
  multiple?: boolean; // Defaults to false
  initialFiles?: FileMetadata[];
  onFilesChangeAction?: (files: FileWithPreview[]) => void; // Callback when files change
  onFilesAddedAction?: (addedFiles: FileWithPreview[]) => void; // Callback when new files are added
};

export type FileUploadState = {
  files: FileWithPreview[];
  isDragging: boolean;
  errors: string[];
};

export type FileUploadActions = {
  addFiles: (files: FileList | File[]) => void;
  removeFile: (id: string) => void;
  clearFiles: () => void;
  clearErrors: () => void;
  handleDragEnter: (e: DragEvent<HTMLElement>) => void;
  handleDragLeave: (e: DragEvent<HTMLElement>) => void;
  handleDragOver: (e: DragEvent<HTMLElement>) => void;
  handleDrop: (e: DragEvent<HTMLElement>) => void;
  handleFileChange: (e: ChangeEvent<HTMLInputElement>) => void;
  openFileDialog: () => void;
  getInputProps: (props?: InputHTMLAttributes<HTMLInputElement>) => InputHTMLAttributes<HTMLInputElement> & {
    // biome-ignore lint/suspicious/noExplicitAny: intentional
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    ref: any;
  };
};

export function useFileUpload(options: FileUploadOptions = {}): [FileUploadState, FileUploadActions] {
  const {
    maxFiles = Number.POSITIVE_INFINITY,
    maxSize = Number.POSITIVE_INFINITY,
    accept = "*",
    multiple = false,
    initialFiles = [],
    onFilesChangeAction: onFilesChange,
    onFilesAddedAction: onFilesAdded,
  } = options;

  const [state, setState] = useState<FileUploadState>({
    errors: [],
    files: initialFiles.map(file => ({
      file,
      id: file.id,
      preview: file.url,
    })),
    isDragging: false,
  });

  const inputRef = useRef<HTMLInputElement>(null);

  const validateFile = useCallback(
    (file: File | FileMetadata): string | null => {
      if (file instanceof File) {
        if (file.size > maxSize) {
          return `File "${file.name}" exceeds the maximum size of ${formatBytes(maxSize)}.`;
        }
      }
      else {
        if (file.size > maxSize) {
          return `File "${file.name}" exceeds the maximum size of ${formatBytes(maxSize)}.`;
        }
      }

      if (accept !== "*") {
        const acceptedTypes = accept.split(",").map(type => type.trim());
        const fileType = file instanceof File ? file.type || "" : file.type;
        const fileExtension = `.${file instanceof File ? file.name.split(".").pop() : file.name.split(".").pop()}`;

        const isAccepted = acceptedTypes.some((type) => {
          if (type.startsWith(".")) {
            return fileExtension.toLowerCase() === type.toLowerCase();
          }
          if (type.endsWith("/*")) {
            const baseType = type.split("/")[0];
            return fileType.startsWith(`${baseType}/`);
          }
          return fileType === type;
        });

        if (!isAccepted) {
          return `File "${file instanceof File ? file.name : file.name}" is not an accepted file type.`;
        }
      }

      return null;
    },
    [accept, maxSize],
  );

  const createPreview = useCallback((file: File | FileMetadata): string | undefined => {
    if (file instanceof File) {
      return URL.createObjectURL(file);
    }
    return file.url;
  }, []);

  const generateUniqueId = useCallback((file: File | FileMetadata): string => {
    if (file instanceof File) {
      return `${file.name}-${Date.now()}-${Math.random().toString(36).substring(2, 9)}`;
    }
    return file.id;
  }, []);

  const clearFiles = useCallback(() => {
    setState((prev) => {
      // Clean up object URLs
      for (const file of prev.files ?? []) {
        if (file.preview && file.file instanceof File && file.file.type.startsWith("image/")) {
          URL.revokeObjectURL(file.preview);
        }
      }

      if (inputRef.current) {
        inputRef.current.value = "";
      }

      const newState = {
        ...prev,
        errors: [],
        files: [],
      };

      onFilesChange?.(newState.files);
      return newState;
    });
  }, [onFilesChange]);

  const addFiles = useCallback(
    (newFiles: FileList | File[]) => {
      if (!newFiles || newFiles.length === 0)
        return;

      const newFilesArray = Array.from(newFiles);
      const errors: string[] = [];

      // Clear existing errors when new files are uploaded
      setState(prev => ({ ...prev, errors: [] }));

      // In single file mode, clear existing files first
      if (!multiple) {
        clearFiles();
      }

      // Check if adding these files would exceed maxFiles (only in multiple mode)
      if (multiple && maxFiles !== Number.POSITIVE_INFINITY && state.files.length + newFilesArray.length > maxFiles) {
        errors.push(`You can only upload a maximum of ${maxFiles} files.`);
        setState(prev => ({ ...prev, errors }));
        return;
      }

      const validFiles: FileWithPreview[] = [];

      for (const file of newFilesArray) {
        if (multiple) {
          const isDuplicate = state.files.some(
            existingFile => existingFile.file.name === file.name && existingFile.file.size === file.size,
          );

          if (isDuplicate) {
            continue;
          }
        }

        if (file.size > maxSize) {
          errors.push(
            multiple
              ? `Some files exceed the maximum size of ${formatBytes(maxSize)}.`
              : `File exceeds the maximum size of ${formatBytes(maxSize)}.`,
          );
          continue;
        }

        const error = validateFile(file);

        if (error) {
          errors.push(error);
          continue;
        }

        validFiles.push({
          file,
          id: generateUniqueId(file),
          preview: createPreview(file),
        });
      }

      // Only update state if we have valid files to add
      if (validFiles.length > 0) {
        // Call the onFilesAdded callback with the newly added valid files
        onFilesAdded?.(validFiles);

        setState((prev) => {
          const newFiles = !multiple ? validFiles : [...prev.files, ...validFiles];
          onFilesChange?.(newFiles);
          return {
            ...prev,
            errors,
            files: newFiles,
          };
        });
      }
      else if (errors.length > 0) {
        setState(prev => ({
          ...prev,
          errors,
        }));
      }

      // Reset input value after handling files
      if (inputRef.current) {
        inputRef.current.value = "";
      }
    },
    [state.files, maxFiles, multiple, maxSize, validateFile, createPreview, generateUniqueId, clearFiles, onFilesChange, onFilesAdded],
  );

  const removeFile = useCallback(
    (id: string) => {
      setState((prev) => {
        const fileToRemove = prev.files.find(file => file.id === id);
        if (fileToRemove?.preview && fileToRemove.file instanceof File && fileToRemove.file.type.startsWith("image/")) {
          URL.revokeObjectURL(fileToRemove.preview);
        }

        const newFiles = prev.files.filter(file => file.id !== id);
        onFilesChange?.(newFiles);

        return {
          ...prev,
          errors: [],
          files: newFiles,
        };
      });
    },
    [onFilesChange],
  );

  const clearErrors = useCallback(() => {
    setState(prev => ({
      ...prev,
      errors: [],
    }));
  }, []);

  const handleDragEnter = useCallback((e: DragEvent<HTMLElement>) => {
    e.preventDefault();
    e.stopPropagation();
    setState(prev => ({ ...prev, isDragging: true }));
  }, []);

  const handleDragLeave = useCallback((e: DragEvent<HTMLElement>) => {
    e.preventDefault();
    e.stopPropagation();

    if (e.currentTarget.contains(e.relatedTarget as Node)) {
      return;
    }

    setState(prev => ({ ...prev, isDragging: false }));
  }, []);

  const handleDragOver = useCallback((e: DragEvent<HTMLElement>) => {
    e.preventDefault();
    e.stopPropagation();
  }, []);

  const handleDrop = useCallback(
    (e: DragEvent<HTMLElement>) => {
      e.preventDefault();
      e.stopPropagation();
      setState(prev => ({ ...prev, isDragging: false }));

      // Don't process files if the input is disabled
      if (inputRef.current?.disabled) {
        return;
      }

      if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
        // In single file mode, only use the first file
        if (!multiple) {
          const file = e.dataTransfer.files[0];
          addFiles([file]);
        }
        else {
          addFiles(e.dataTransfer.files);
        }
      }
    },
    [addFiles, multiple],
  );

  const handleFileChange = useCallback(
    (e: ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files.length > 0) {
        addFiles(e.target.files);
      }
    },
    [addFiles],
  );

  const openFileDialog = useCallback(() => {
    if (inputRef.current) {
      inputRef.current.click();
    }
  }, []);

  const getInputProps = useCallback(
    (props: InputHTMLAttributes<HTMLInputElement> = {}) => {
      return {
        ...props,
        accept: props.accept || accept,
        multiple: props.multiple !== undefined ? props.multiple : multiple,
        onChange: handleFileChange,
        ref: inputRef,
        type: "file" as const,
      };
    },
    [accept, multiple, handleFileChange],
  );

  return [
    state,
    {
      addFiles,
      clearErrors,
      clearFiles,
      getInputProps,
      handleDragEnter,
      handleDragLeave,
      handleDragOver,
      handleDrop,
      handleFileChange,
      openFileDialog,
      removeFile,
    },
  ];
}

// Helper function to format bytes to human-readable format
export function formatBytes(bytes: number, decimals = 2): string {
  if (bytes === 0)
    return "0 Bytes";

  const k = 1024;
  const dm = decimals < 0 ? 0 : decimals;
  const sizes = ["Bytes", "KB", "MB", "GB", "TB", "PB", "EB", "ZB", "YB"];

  const i = Math.floor(Math.log(bytes) / Math.log(k));

  return Number.parseFloat((bytes / k ** i).toFixed(dm)) + sizes[i];
}

import { useCallback, useEffect, useRef, useState } from "react";

import useCallbackRef from "@/hooks/use-callback-ref";

function containsRelatedTarget(event: FocusEvent) {
  if (event.currentTarget instanceof HTMLElement && event.relatedTarget instanceof HTMLElement) {
    return event.currentTarget.contains(event.relatedTarget);
  }

  return false;
}

export type UseFocusWithinOptions = {
  onFocus?: (event: FocusEvent) => void;
  onBlur?: (event: FocusEvent) => void;
};

export type UseFocusWithinReturnValue<T extends HTMLElement = HTMLElement> = {
  ref: React.RefCallback<T | null>;
  focused: boolean;
};

function useFocusWithin<T extends HTMLElement = HTMLElement>({
  onBlur,
  onFocus,
}: UseFocusWithinOptions = {}): UseFocusWithinReturnValue<T> {
  const [focused, setFocused] = useState(false);
  const focusedRef = useRef(false);
  const previousNode = useRef<T | null>(null);

  const onFocusRef = useCallbackRef(onFocus);
  const onBlurRef = useCallbackRef(onBlur);

  const _setFocused = useCallback((value: boolean) => {
    setFocused(value);
    focusedRef.current = value;
  }, []);

  const handleFocusIn = useCallback((event: FocusEvent) => {
    if (!focusedRef.current) {
      _setFocused(true);
      onFocusRef(event);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleFocusOut = useCallback((event: FocusEvent) => {
    if (focusedRef.current && !containsRelatedTarget(event)) {
      _setFocused(false);
      onBlurRef(event);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const callbackRef: React.RefCallback<T | null> = useCallback(
    (node) => {
      if (!node) {
        return;
      }

      if (previousNode.current) {
        previousNode.current.removeEventListener("focusin", handleFocusIn);
        previousNode.current.removeEventListener("focusout", handleFocusOut);
      }

      node.addEventListener("focusin", handleFocusIn);
      node.addEventListener("focusout", handleFocusOut);
      previousNode.current = node;
    },
    [handleFocusIn, handleFocusOut],
  );

  useEffect(
    () => () => {
      if (previousNode.current) {
        previousNode.current.removeEventListener("focusin", handleFocusIn);
        previousNode.current.removeEventListener("focusout", handleFocusOut);
      }
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [],
  );

  return { ref: callbackRef, focused };
}

export default useFocusWithin;

import { useEffect, useRef, useState } from "react";

type UseFpsType = {
  every?: number;
};

function useFps(options?: UseFpsType) {
  const { every = 10 } = options ?? {};
  const [fps, setFps] = useState<number>(0);
  const frameRef = useRef<number | null>(null);

  useEffect(() => {
    let frameCount = 0;
    let lastFpsUpdate = performance.now();

    const measureFps = () => {
      const now = performance.now();
      frameCount++;

      // Update FPS every x frames
      if (frameCount >= every) {
        const timeDiff = now - lastFpsUpdate;
        // Avoid division by zero or very small numbers
        const currentFps = timeDiff > 0 ? Math.round((frameCount * 1000) / timeDiff) : 0;
        setFps(currentFps);
        frameCount = 0;
        lastFpsUpdate = now;
      }

      frameRef.current = requestAnimationFrame(measureFps);
    };

    frameRef.current = requestAnimationFrame(measureFps);

    return () => {
      if (frameRef.current) {
        cancelAnimationFrame(frameRef.current);
      }
    };
  }, [every]);

  return fps;
}

export default useFps;

import type { RefCallback } from "react";

import { useCallback, useEffect, useRef, useState } from "react";

type PrefixedDocument = {
  webkitFullscreenElement?: Element | null;
  mozFullScreenElement?: Element | null;
  msFullscreenElement?: Element | null;
  webkitExitFullscreen?: () => Promise<void>;
  msExitFullscreen?: () => Promise<void>;
  mozCancelFullScreen?: () => Promise<void>;
} & Document;

type PrefixedElement = {
  webkitRequestFullscreen?: () => Promise<void>;
  webkitEnterFullscreen?: () => Promise<void>;
  msRequestFullscreen?: () => Promise<void>;
  mozRequestFullscreen?: () => Promise<void>;
} & HTMLElement;

function getFullscreenElement(): Element | null {
  const doc = document as PrefixedDocument;
  return doc.fullscreenElement ?? doc.webkitFullscreenElement ?? doc.mozFullScreenElement ?? doc.msFullscreenElement ?? null;
}

function exitFullscreen(): Promise<void> {
  const doc = document as PrefixedDocument;

  if (typeof doc.exitFullscreen === "function")
    return doc.exitFullscreen();
  if (typeof doc.msExitFullscreen === "function")
    return doc.msExitFullscreen();
  if (typeof doc.webkitExitFullscreen === "function")
    return doc.webkitExitFullscreen();
  if (typeof doc.mozCancelFullScreen === "function")
    return doc.mozCancelFullScreen();

  return Promise.resolve();
}

function enterFullScreen(element: HTMLElement): Promise<void> {
  const el = element as PrefixedElement;

  const fn
    = el.requestFullscreen ?? el.msRequestFullscreen ?? el.webkitEnterFullscreen ?? el.webkitRequestFullscreen ?? el.mozRequestFullscreen;

  return fn ? fn.call(el) : Promise.resolve();
}

const prefixes = ["", "webkit", "moz", "ms"] as const;

type FullscreenEvents = {
  onFullScreen: (event: Event) => void;
  onError: (event: Event) => void;
};

function addEvents(element: HTMLElement, events: FullscreenEvents) {
  const { onFullScreen, onError } = events;
  prefixes.forEach((prefix) => {
    element.addEventListener(`${prefix}fullscreenchange`, onFullScreen);
    element.addEventListener(`${prefix}fullscreenerror`, onError);
  });

  return () => removeEvents(element, events);
}

function removeEvents(element: HTMLElement, { onFullScreen, onError }: FullscreenEvents) {
  prefixes.forEach((prefix) => {
    element.removeEventListener(`${prefix}fullscreenchange`, onFullScreen);
    element.removeEventListener(`${prefix}fullscreenerror`, onError);
  });
}

// --- Element-scoped fullscreen ---

export type UseFullscreenElementReturnValue<T extends HTMLElement> = {
  ref: RefCallback<T | null>;
  toggle: () => Promise<void>;
  fullscreen: boolean;
};

export function useFullscreenElement<T extends HTMLElement = HTMLDivElement>(): UseFullscreenElementReturnValue<T> {
  const [fullscreen, setFullscreen] = useState(false);
  const refElement = useRef<T | null>(null);
  const prevNodeRef = useRef<T | null>(null);

  const handleFullscreenChange = useCallback(() => {
    setFullscreen(refElement.current === getFullscreenElement());
  }, []);

  const handleFullscreenError = useCallback(() => {
    setFullscreen(false);
  }, []);

  const toggle = useCallback(async () => {
    if (!getFullscreenElement() && refElement.current) {
      await enterFullScreen(refElement.current);
    }
    else {
      await exitFullscreen();
    }
  }, []);

  const refCallback: RefCallback<T | null> = useCallback((node) => {
    if (prevNodeRef.current && prevNodeRef.current !== node) {
      removeEvents(prevNodeRef.current, {
        onFullScreen: handleFullscreenChange,
        onError: handleFullscreenError,
      });
    }

    if (node) {
      addEvents(node, {
        onFullScreen: handleFullscreenChange,
        onError: handleFullscreenError,
      });
    }

    refElement.current = node;
    prevNodeRef.current = node;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return { ref: refCallback, toggle, fullscreen };
}

// --- Document-scoped fullscreen ---

export type UseFullscreenDocumentReturnValue = {
  toggle: () => Promise<void>;
  fullscreen: boolean;
};

export function useFullscreenDocument(): UseFullscreenDocumentReturnValue {
  const [fullscreen, setFullscreen] = useState(false);

  const handleFullscreenChange = useCallback(() => {
    setFullscreen(getFullscreenElement() === document.documentElement);
  }, []);

  const handleFullscreenError = useCallback(() => {
    setFullscreen(false);
  }, []);

  const toggle = useCallback(async () => {
    if (!getFullscreenElement()) {
      await enterFullScreen(document.documentElement);
    }
    else {
      await exitFullscreen();
    }
  }, []);

  useEffect(() => {
    return addEvents(document.documentElement, {
      onFullScreen: handleFullscreenChange,
      onError: handleFullscreenError,
    });
  }, [handleFullscreenChange, handleFullscreenError]);

  return { toggle, fullscreen };
}

import { useCallback, useState } from "react";

import useIsomorphicLayoutEffect from "@/hooks/use-isomorphic-layout-effect";

type UseHashReturn = [string, (newHash: string) => void];

function useHash(): UseHashReturn {
  const [hash, setHash] = useState(() => window.location.hash);

  const onHashChange = useCallback(() => {
    setHash(window.location.hash);
  }, []);

  useIsomorphicLayoutEffect(() => {
    window.addEventListener("hashchange", onHashChange);
    return () => {
      window.removeEventListener("hashchange", onHashChange);
    };
  }, []);

  const _setHash = useCallback(
    (newHash: string) => {
      if (newHash !== hash) {
        window.location.hash = newHash;
      }
    },
    [hash],
  );

  return [hash, _setHash] as const;
}

export default useHash;

import { useSyncExternalStore } from "react";

/**
 *
 * @returns {boolean} Is navigator online
 */
function getSnapshot(): boolean | null {
  if (typeof window === "undefined") {
    return null;
  }

  return navigator.onLine;
}

function subscribe(onStoreChange: () => void): () => void {
  if (typeof window !== "undefined") {
    window.addEventListener("online", onStoreChange);
    window.addEventListener("offline", onStoreChange);
    return () => {
      window.removeEventListener("online", onStoreChange);
      window.removeEventListener("offline", onStoreChange);
    };
  }
  else {
    console.warn("useOnline: window is undefined.");
    return () => {};
  }
}

function useIsOnline(): boolean | null {
  const isOnline = useSyncExternalStore<boolean | null>(subscribe, getSnapshot);

  return isOnline;
}
export default useIsOnline;

import { useState } from "react";

import useIsomorphicLayoutEffect from "@/hooks/use-isomorphic-layout-effect";

export type UseOSReturnValue = "undetermined" | "macos" | "ios" | "windows" | "android" | "linux" | "chromeos";

function isMacOS(userAgent: string): boolean {
  const macosPattern = /(Macintosh)|(MacIntel)|(MacPPC)|(Mac68K)/i;

  return macosPattern.test(userAgent);
}

function isIOS(userAgent: string): boolean {
  const iosPattern = /(iPhone)|(iPad)|(iPod)/i;

  return iosPattern.test(userAgent);
}

function isWindows(userAgent: string): boolean {
  const windowsPattern = /(Win32)|(Win64)|(Windows)|(WinCE)/i;

  return windowsPattern.test(userAgent);
}

function isAndroid(userAgent: string): boolean {
  const androidPattern = /Android/i;

  return androidPattern.test(userAgent);
}

function isLinux(userAgent: string): boolean {
  const linuxPattern = /Linux/i;

  return linuxPattern.test(userAgent);
}

function isChromeOS(userAgent: string): boolean {
  const chromePattern = /CrOS/i;
  return chromePattern.test(userAgent);
}

function getOS(): UseOSReturnValue {
  if (typeof window === "undefined") {
    return "undetermined";
  }

  const { userAgent } = window.navigator;

  if (isIOS(userAgent) || (isMacOS(userAgent) && "ontouchend" in document)) {
    return "ios";
  }
  if (isMacOS(userAgent)) {
    return "macos";
  }
  if (isWindows(userAgent)) {
    return "windows";
  }
  if (isAndroid(userAgent)) {
    return "android";
  }
  if (isChromeOS(userAgent)) {
    return "chromeos";
  }
  if (isLinux(userAgent)) {
    return "linux";
  }

  return "undetermined";
}

export type UseOsOptions = {
  getValueInEffect: boolean;
};

export function useOs(options: UseOsOptions = { getValueInEffect: true }): UseOSReturnValue {
  const [value, setValue] = useState<UseOSReturnValue>(options.getValueInEffect ? "undetermined" : getOS());

  useIsomorphicLayoutEffect(() => {
    if (options.getValueInEffect) {
      setValue(getOS);
    }
  }, []);

  return value;
}

export default useOs;

import useMediaQuery from "@/hooks/use-media-query";

function useReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

export default useReducedMotion;

import { useEffect, useEffectEvent, useRef, useState } from "react";

export type ScrollDirection = "up" | "down" | "unknown";

function useScrollDirection(): ScrollDirection {
  const lastScrollTopRef = useRef(0);
  const [scrollDirection, setScrollDirection] = useState<ScrollDirection>("unknown");
  const isResizingRef = useRef(false);
  const resizeTimerRef = useRef<number | undefined>(undefined);

  const handleScroll = useEffectEvent(() => {
    if (isResizingRef.current) {
      return;
    }

    const currentScrollTop = window.scrollY || document.documentElement.scrollTop;
    setScrollDirection(currentScrollTop < lastScrollTopRef.current ? "up" : "down");
    lastScrollTopRef.current = currentScrollTop;
  });

  useEffect(() => {
    const handleResize = () => {
      isResizingRef.current = true;
      window.clearTimeout(resizeTimerRef.current);
      resizeTimerRef.current = window.setTimeout(() => {
        isResizingRef.current = false;
      }, 300);
    };

    window.addEventListener("scroll", handleScroll);
    window.addEventListener("resize", handleResize);

    return () => {
      window.removeEventListener("scroll", handleScroll);
      window.removeEventListener("resize", handleResize);
      clearTimeout(resizeTimerRef.current);
    };
  }, []);

  return scrollDirection;
}

export default useScrollDirection;

import { useRef, useState } from "react";

import useIsomorphicLayoutEffect from "@/hooks/use-isomorphic-layout-effect";

type UseScrollLockOptions = {
  autoLock?: boolean;
  lockTarget?: HTMLElement | string;
  widthReflow?: boolean;
};

type UseScrollLockReturn = {
  isLocked: boolean;
  lock: () => void;
  unlock: () => void;
};

type OriginalStyle = {
  overflow: CSSStyleDeclaration["overflow"];
  paddingRight: CSSStyleDeclaration["paddingRight"];
};

const IS_SERVER = typeof window === "undefined";

/**
 * Hook to handle scroll locking.
 * @param {UseScrollLockOptions} options - The options for the hook.
 * @returns {UseScrollLockReturn} An object containing the current state of the scroll lock and functions to control it.
 */
export default function useScrollLock(options: UseScrollLockOptions = {}): UseScrollLockReturn {
  const { autoLock = true, lockTarget, widthReflow = true } = options;
  const [isLocked, setIsLocked] = useState(false);
  const target = useRef<HTMLElement | null>(null);
  const originalStyle = useRef<OriginalStyle | null>(null);

  const lock = () => {
    if (target.current) {
      const { overflow, paddingRight } = target.current.style;

      // Save the original styles
      originalStyle.current = { overflow, paddingRight };

      // Prevent width reflow
      if (widthReflow) {
        // Use window inner width if body is the target as global scrollbar isn't part of the document
        const offsetWidth = target.current === document.body ? window.innerWidth : target.current.offsetWidth;
        // Get current computed padding right in pixels
        const currentPaddingRight = Number.parseInt(window.getComputedStyle(target.current).paddingRight, 10) || 0;

        const scrollbarWidth = offsetWidth - target.current.scrollWidth;
        target.current.style.paddingRight = `${scrollbarWidth + currentPaddingRight}px`;
      }

      // Lock the scroll
      target.current.style.overflow = "hidden";

      setIsLocked(true);
    }
  };

  const unlock = () => {
    if (target.current && originalStyle.current) {
      target.current.style.overflow = originalStyle.current.overflow;

      // Only reset padding right if we changed it
      if (widthReflow) {
        target.current.style.paddingRight = originalStyle.current.paddingRight;
      }
    }

    setIsLocked(false);
  };

  useIsomorphicLayoutEffect(() => {
    if (IS_SERVER)
      return;

    if (lockTarget) {
      target.current = typeof lockTarget === "string" ? document.querySelector(lockTarget) : lockTarget;
    }

    if (!target.current) {
      target.current = document.body;
    }

    if (autoLock) {
      lock();
    }

    return () => {
      unlock();
    };
  }, [autoLock, lockTarget, widthReflow]);

  return { isLocked, lock, unlock };
}

import { useCallback, useEffect, useState } from "react";

type SelectionRect = {
  top: number;
  left: number;
  width: number;
  height: number;
};

function useTextSelection() {
  const [text, setText] = useState("");
  const [rect, setRect] = useState<SelectionRect | null>(null);

  const handleSelectionChange = useCallback(() => {
    const selection = window.getSelection();

    // Clear state if no valid selection exists
    if (!selection || selection.isCollapsed || !selection.toString().trim()) {
      setText("");
      setRect(null);
      return;
    }

    const selectedText = selection.toString();
    const range = selection.getRangeAt(0);
    const clientRect = range.getBoundingClientRect();

    setText(selectedText);
    setRect({
      top: clientRect.top + window.scrollY,
      left: clientRect.left + window.scrollX,
      width: clientRect.width,
      height: clientRect.height,
    });
  }, []);

  useEffect(() => {
    // Listen to native DOM selection changes
    document.addEventListener("selectionchange", handleSelectionChange);
    return () => {
      document.removeEventListener("selectionchange", handleSelectionChange);
    };
  }, [handleSelectionChange]);

  return { text, rect };
}

export default useTextSelection;

import { useEffect, useRef } from "react";

function useWindowEvent<K extends keyof WindowEventMap, R>(
  type: K,
  listener: (this: Window, ev: WindowEventMap[K]) => R,
  options?: boolean | AddEventListenerOptions,
): void {
  const listenerRef = useRef(listener);

  useEffect(() => {
    listenerRef.current = listener;
  }, [listener]);

  useEffect(() => {
    const eventListener = (event: WindowEventMap[K]) => {
      listenerRef.current.call(window, event);
    };

    window.addEventListener(type, eventListener, options);

    return () => {
      window.removeEventListener(type, eventListener, options);
    };
  }, [type, options]);
}

export default useWindowEvent;
